import{_ as a,c as t,o as r,ak as i,am as s}from"./chunks/framework.B95DSy-a.js";const f=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v1-114-1.md","filePath":"aireblock-releases/aireframe-v1-114-1.md","lastUpdated":1772546822000}'),o={name:"aireblock-releases/aireframe-v1-114-1.md"};function l(n,e,c,d,h,m){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+s+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.44.1<br><strong>Release Date:</strong> 4 March 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Regenerate AI Summary from Dashboard (FRAME-2418)</li><li>Theme Caching for Improved Resilience (FRAME-2468)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>More Relevant Search Results (FRAME-2486)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Smoother Navigation to Configuration Page (FRAME-2406)</li><li>Structural Entity Picker Performance Fix (FRAME-2474)</li><li>Reliable Visualisation Data Updates (FRAME-2476)</li><li>Live Subject List Data Refresh (FRAME-2477)</li><li>Data Extract List Now Shows All Extracts (FRAME-2484)</li><li>Escape Key Behaviour in Code Editor (FRAME-2485)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="regenerate-ai-summary-from-dashboard-frame-2418" tabindex="-1">Regenerate AI Summary from Dashboard (FRAME-2418) <a class="header-anchor" href="#regenerate-ai-summary-from-dashboard-frame-2418" aria-label="Permalink to “Regenerate AI Summary from Dashboard (FRAME-2418)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Added the ability to regenerate AI-generated summaries from the data summary widget on dashboards. Previously, once a summary was created it could not be refreshed. Users can now trigger a new summary on demand.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If an AI-generated summary on your dashboard is unclear or out of date, you can now regenerate it with a single click. You no longer need to wait or work around a summary that doesn&#39;t reflect the latest information.</p></div><h4 id="theme-caching-for-improved-resilience-frame-2468" tabindex="-1">Theme Caching for Improved Resilience (FRAME-2468) <a class="header-anchor" href="#theme-caching-for-improved-resilience-frame-2468" aria-label="Permalink to “Theme Caching for Improved Resilience (FRAME-2468)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireFrame now caches the theme retrieved from AireTheme, reducing the number of requests made to the theming service. The cache refreshes periodically and retains the last known theme if AireTheme is temporarily unavailable, rather than reverting to defaults.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your branding and visual theme will load faster and remain consistent, even during brief periods of service disruption. You should no longer see the interface momentarily flash back to default styling.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="more-relevant-search-results-frame-2486" tabindex="-1">More Relevant Search Results (FRAME-2486) <a class="header-anchor" href="#more-relevant-search-results-frame-2486" aria-label="Permalink to “More Relevant Search Results (FRAME-2486)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Increased the word similarity threshold used in search queries to filter out loosely matched results, ensuring that only more closely relevant items are returned.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When you search within AireFrame, you will see fewer irrelevant results and find what you are looking for more quickly.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="smoother-navigation-to-configuration-page-frame-2406" tabindex="-1">Smoother Navigation to Configuration Page (FRAME-2406) <a class="header-anchor" href="#smoother-navigation-to-configuration-page-frame-2406" aria-label="Permalink to “Smoother Navigation to Configuration Page (FRAME-2406)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an unexpected scrolling animation caused by the footer when navigating from the home page to the configuration page.</p></div><h4 id="structural-entity-picker-performance-fix-frame-2474" tabindex="-1">Structural Entity Picker Performance Fix (FRAME-2474) <a class="header-anchor" href="#structural-entity-picker-performance-fix-frame-2474" aria-label="Permalink to “Structural Entity Picker Performance Fix (FRAME-2474)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Resolved an issue where the structural entity picker was continuously re-rendering and making repeated data requests when no value was selected, causing unnecessary load.</p></div><h4 id="reliable-visualisation-data-updates-frame-2476" tabindex="-1">Reliable Visualisation Data Updates (FRAME-2476) <a class="header-anchor" href="#reliable-visualisation-data-updates-frame-2476" aria-label="Permalink to “Reliable Visualisation Data Updates (FRAME-2476)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Changed the visualisation data handling so that when configuration is updated, existing data sets are marked as stale rather than immediately deleted. Data is recalculated on demand when next accessed, spreading the processing load and avoiding database locks on large tenants.</p></div><h4 id="live-subject-list-data-refresh-frame-2477" tabindex="-1">Live Subject List Data Refresh (FRAME-2477) <a class="header-anchor" href="#live-subject-list-data-refresh-frame-2477" aria-label="Permalink to “Live Subject List Data Refresh (FRAME-2477)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where Subject List V2 dashboards did not automatically refresh when underlying data was updated. The subscription mechanism now correctly triggers a data refetch for subject list notifications, and unnecessary per-subject subscriptions have been removed to reduce server load.</p></div><h4 id="data-extract-list-now-shows-all-extracts-frame-2484" tabindex="-1">Data Extract List Now Shows All Extracts (FRAME-2484) <a class="header-anchor" href="#data-extract-list-now-shows-all-extracts-frame-2484" aria-label="Permalink to “Data Extract List Now Shows All Extracts (FRAME-2484)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a filtering issue that caused the data extract list to only display source data extracts, hiding all other extract types from the list.</p></div><h4 id="escape-key-behaviour-in-code-editor-frame-2485" tabindex="-1">Escape Key Behaviour in Code Editor (FRAME-2485) <a class="header-anchor" href="#escape-key-behaviour-in-code-editor-frame-2485" aria-label="Permalink to “Escape Key Behaviour in Code Editor (FRAME-2485)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue in the Monaco code editor where pressing the Escape key while the autocomplete popup was open would close the entire editor instead of just dismissing the autocomplete suggestions.</p></div>',38)])])}const p=a(o,[["render",l]]);export{f as __pageData,p as default};
